const mysql = require('mysql2/promise');

// BAD: String concatenation (vulnerable to SQL injection)
app.get('/users/bad', async (req, res) => {
  const username = req.query.username;
  const query = `SELECT * FROM users WHERE username = '${username}'`; // VULNERABLE!
  const [rows] = await db.query(query);
  res.json(rows);
});

// GOOD: Parameterized query (safe)
app.get('/users/safe', async (req, res) => {
  const username = req.query.username;
  const query = 'SELECT * FROM users WHERE username = ?';
  const [rows] = await db.query(query, [username]); // SAFE
  res.json(rows);
});

// GOOD: Named parameters (PostgreSQL)
const { Pool } = require('pg');
const pool = new Pool();

app.get('/users/pg', async (req, res) => {
  const username = req.query.username;
  const query = 'SELECT * FROM users WHERE username = $1';
  const result = await pool.query(query, [username]); // SAFE
  res.json(result.rows);
});

const { Sequelize, DataTypes } = require('sequelize');
const sequelize = new Sequelize('database', 'username', 'password', {
  host: 'localhost',
  dialect: 'mysql'
});

// Define model
const User = sequelize.define('User', {
  username: DataTypes.STRING,
  email: DataTypes.STRING
});

// SAFE: Sequelize automatically parameterizes queries
app.get('/users', async (req, res) => {
  const username = req.query.username;

  // Method 1: findOne (safe)
  const user = await User.findOne({
    where: { username: username }
  });

  // Method 2: findAll with operators (safe)
  const users = await User.findAll({
    where: {
      username: {
        [Sequelize.Op.like]: `%${username}%` // Still safe with ORM
      }
    }
  });

  res.json(users);
});

// WARNING: Raw queries still need parameterization
app.get('/users/raw', async (req, res) => {
  const username = req.query.username;

  // GOOD: Parameterized raw query
  const [results] = await sequelize.query(
    'SELECT * FROM users WHERE username = ?',
    {
      replacements: [username], // Safe
      type: Sequelize.QueryTypes.SELECT
    }
  );

  res.json(results);
});

const { query, validationResult } = require('express-validator');

// Input validation middleware
app.get('/users',
  // Validate username: alphanumeric only, 3-20 characters
  query('username')
    .isAlphanumeric()
    .isLength({ min: 3, max: 20 })
    .trim()
    .escape(),

  async (req, res) => {
    // Check validation results
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    // Safe to use (but still use parameterized queries!)
    const username = req.query.username;
    const query = 'SELECT * FROM users WHERE username = ?';
    const [rows] = await db.query(query, [username]);
    res.json(rows);
  }
);

// Alternative: Joi validation
const Joi = require('joi');

const userQuerySchema = Joi.object({
  username: Joi.string().alphanum().min(3).max(20).required(),
  email: Joi.string().email().optional()
});

app.get('/users/joi', async (req, res) => {
  const { error, value } = userQuerySchema.validate(req.query);

  if (error) {
    return res.status(400).json({ error: error.details[0].message });
  }

  const query = 'SELECT * FROM users WHERE username = ?';
  const [rows] = await db.query(query, [value.username]);
  res.json(rows);
});
